content.text:
/* === D&D 2024 App — Dark Fantasy Theme === */

:root {
  --bg-base: #0a0e1a;
  --bg-surface: #111827;
  --bg-card: #1a2035;
  --bg-hover: #1e2a42;
  --bg-input: #0d1321;
  --gold: #F59E0B;
  --gold-dim: #D97706;
  --gold-bright: #FBBF24;
  --red: #EF4444;
  --red-dim: #B91C1C;
  --green: #10B981;
  --green-dim: #059669;
  --blue: #3B82F6;
  --purple: #8B5CF6;
  --text: #E5E7EB;
  --text-dim: #9CA3AF;
  --text-muted: #6B7280;
  --border: #374151;
  --border-gold: rgba(245, 158, 11, 0.3);
  --shadow: 0 4px 24px rgba(0,0,0,0.4);
  --radius: 8px;
  --radius-lg: 12px;
  --mobile-header-h: 50px;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  background: var(--bg-base);
  color: var(--text);
  min-height: 100vh;
  overflow-x: hidden;
}

.cinzel { font-family: 'Cinzel', serif; }

/* === Scrollbar === */
::-webkit-scrollbar { width: 8px; height: 8px; }
::-webkit-scrollbar-track { background: var(--bg-base); }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: var(--gold-dim); }

/* === Screens === */
.screen { display: none; }
.screen.active { display: flex; }

/* === LOGIN === */
#login-screen {
  min-height: 100vh;
  align-items: center;
  justify-content: center;
  background: radial-gradient(ellipse at center, #141b2d 0%, #0a0e1a 70%);
}

.login-container {
  background: var(--bg-card);
  border: 1px solid var(--border-gold);
  border-radius: var(--radius-lg);
  padding: 2.5rem;
  width: 420px;
  max-width: 95vw;
  box-shadow: var(--shadow), 0 0 60px rgba(245,158,11,0.05);
}

.login-logo {
  text-align: center;
  margin-bottom: 2rem;
}

.dragon-icon {
  font-size: 4rem;
  margin-bottom: 0.5rem;
  filter: drop-shadow(0 0 20px rgba(245,158,11,0.3));
}

.login-logo h1 {
  color: var(--gold);
  font-size: 2rem;
  letter-spacing: 4px;
  text-shadow: 0 0 30px rgba(245,158,11,0.2);
}

.login-logo .subtitle {
  color: var(--text-dim);
  font-size: 0.85rem;
  margin-top: 0.25rem;
  letter-spacing: 2px;
}

.login-tabs {
  display: flex;
  gap: 0;
  margin-bottom: 1.5rem;
  border-radius: var(--radius);
  overflow: hidden;
  border: 1px solid var(--border);

