content.text:
/* === D&D 2024 App — Dark Fantasy Theme === */

:root {
  --bg-base: #0a0e1a;
  --bg-surface: #111827;
  --bg-card: #1a2035;
  --bg-hover: #1e2a42;
  --bg-input: #0d1321;
  --gold: #F59E0B;
  --gold-dim: #D97706;
  --gold-bright: #FBBF24;
  --red: #EF4444;
  --red-dim: #B91C1C;
  --green: #10B981;
  --green-dim: #059669;
  --blue: #3B82F6;
  --purple: #8B5CF6;
  --text: #E5E7EB;
  --text-dim: #9CA3AF;
  --text-muted: #6B7280;
  --border: #374151;
  --border-gold: rgba(245, 158, 11, 0.3);
  --shadow: 0 4px 24px rgba(0,0,0,0.4);
  --radius: 8px;
  --radius-lg: 12px;
  --mobile-header-h: 50px;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  background: var(--bg-base);
  color: var(--text);
  min-height: 100vh;
  overflow-x: hidden;
}

.cinzel { font-family: 'Cinzel', serif; }

